// Resolve today's date in CST and the current CST hour (0-23). The hour is
// stamped on the ingest payload so the edge function writes the snapshot to
// the right (scrape_date, scrape_hour, agent_name) row in intraday_snapshots.
//
// We always scrape TODAY (not yesterday). The ICD actor returns cumulative
// numbers up to the current point in the day, so each hourly run is a
// monotonically growing snapshot — same shape the CRM scraper writes.
function nowCST() {
  const now = new Date();
  const central = new Date(now.toLocaleString('en-US', { timeZone: 'America/Chicago' }));
  const date = central.getFullYear() + '-' + String(central.getMonth() + 1).padStart(2, '0') + '-' + String(central.getDate()).padStart(2, '0');
  return { date, hour: central.getHours() };
}

const { date, hour } = nowCST();
return [{ json: { dates: [date], scrape_hour: hour, mode: 'icd_intraday' } }];

// Fetch active roster + aliases from Supabase. Build the Apify input.
// Identical to the nightly workflow's roster fetch so they stay in sync if
// the agent table changes mid-day.
const ctx = $input.first().json;
const apikey = 'YOUR_SUPABASE_ANON_KEY';
const base = 'https://YOUR_SUPABASE_PROJECT.supabase.co/rest/v1';
const hdr = { apikey };

const [roster, aliases] = await Promise.all([
  this.helpers.httpRequest({ method: 'GET', url: base + '/agents?select=name,is_active&is_active=eq.true', headers: hdr, json: true }),
  this.helpers.httpRequest({ method: 'GET', url: base + '/agent_name_aliases?select=canonical_name,crm_name', headers: hdr, json: true })
]);

if (!roster || roster.length === 0) {
  return [{ json: { error: true, message: 'No active agents found in Supabase', ...ctx } }];
}

const targetAgents = roster.map((a) => a.name);
const nameAliases = {};
for (const a of (aliases || [])) {
  if (a.crm_name && a.canonical_name && a.crm_name !== a.canonical_name) {
    nameAliases[a.crm_name] = a.canonical_name;
  }
}

return [{
  json: {
    ...ctx,
    agentCount: roster.length,
    targetAgents,
    nameAliases,
    apifyBody: JSON.stringify({
      icdUsername: 'YOUR_ICD_USERNAME',
      icdPassword: 'YOUR_ICD_PASSWORD',
      agencyId: '1428',
      backfillDates: ctx.dates,
      targetAgents,
      nameAliases,
      requestDelay: 1500
    })
  }
}];

// Apify run hit a terminal failure (FAILED / ABORTED / TIMED-OUT). Throw so
// this n8n execution is marked FAILED in the executions list (instead of
// silently completing) and any failure-workflow alerts fire.
const data = $input.first().json.data || {};
throw new Error(`ICD run ${data.id || '?'} ended with status=${data.status || 'UNKNOWN'}. Aborting intraday RPA scrape.`);

// Hard cap: bail out of the poll loop if the Apify run has been alive
// longer than MAX_MINUTES. Without this, a stuck run (network blip, hung
// browser, etc.) would loop Wait→Poll→Wait→Poll indefinitely and pile up
// n8n executions. Apify normally transitions to TIMED-OUT on its own — this
// is defense-in-depth.
const MAX_MINUTES = 30;
const data = $input.first().json.data || {};
const status = data.status || 'UNKNOWN';
const startedAt = data.startedAt;
if (startedAt) {
  const elapsedMin = (Date.now() - new Date(startedAt).getTime()) / 60000;
  if (elapsedMin > MAX_MINUTES) {
    throw new Error(`ICD run ${data.id || '?'} exceeded ${MAX_MINUTES}min cap (status=${status}, elapsed=${elapsedMin.toFixed(1)}min). Aborting poll loop.`);
  }
}
return $input.all();

// Pull the dataset from the Apify run and build the icd_intraday payload.
// Threads scrape_hour from the upstream Compute node so the edge function
// writes to the correct hour bucket in intraday_snapshots.
const statusItem = $input.first().json;
const datasetId = statusItem?.data?.defaultDatasetId;
const runId = statusItem?.data?.id || 'unknown';
const scrape_hour = $node['Compute Today + Hour (CST)'].json.scrape_hour;

if (!datasetId) {
  return [{ json: { error: true, message: 'No defaultDatasetId. runId=' + runId } }];
}

const token = 'YOUR_APIFY_TOKEN';
const url = `https://api.apify.com/v2/datasets/${datasetId}/items?token=${token}`;
let items;
for (let attempt = 1; attempt <= 3; attempt++) {
  try {
    const raw = await this.helpers.httpRequest({
      method: 'GET',
      url,
      encoding: 'utf-8',
      timeout: 60000,
      headers: { Accept: 'application/json' },
    });
    items = typeof raw === 'string' ? JSON.parse(raw) : raw;
    if (Array.isArray(items) && items.length > 0) break;
  } catch (err) {
    if (attempt === 3) throw err;
    await new Promise((r) => setTimeout(r, 5000));
  }
}

if (!items || !Array.isArray(items) || items.length === 0) {
  return [{ json: { error: true, message: 'Dataset empty', datasetId, runId } }];
}

const out = [];
for (const item of items) {
  if (item._type === 'icd_calls_report' && Array.isArray(item.agents)) {
    out.push({
      json: {
        scrape_date: item.scrape_date,
        scrape_hour,
        agent_count: item.agents.length,
        unmatched: (item.unmatched_agents || []).length,
        ingestBody: JSON.stringify({
          mode: 'icd_intraday',
          scrape_date: item.scrape_date,
          scrape_hour,
          agents: item.agents.map((a) => ({
            agent_name: a.agent_name,
            ib_leads_delivered: a.billable_leads ?? 0,
            queue_minutes: a.queue_minutes ?? 0,
            inbound_talk_minutes: a.talk_minutes ?? 0,
            avg_wait_minutes: a.avg_wait_minutes ?? 0,
          })),
        }),
      },
    });
  } else if (item._type === 'icd_calls_report_error') {
    out.push({ json: { error: true, scrape_date: item.scrape_date, message: item.error } });
  }
}
if (out.length === 0) return [{ json: { error: true, message: 'No icd_calls_report items in dataset', datasetId, runId } }];
return out;
